                    }
                }
            }
            Err(GpuError::ModuleLoad(msg)) => {
                log::error!("CUDA module load failed: {msg} — using CPU for all frames");
                return Ok(cpu::grade_frame_cpu(pixels, depth, width, height, calibration, params)
                    .map_err(|e| GpuError::CudaFail(e))?);
            }
            Err(e) => return Err(e),
        }
